import React, { useState, useRef, useEffect } from 'react';

export default function Tooltip({ text, children, delay = 200 }) {
  const [open, setOpen] = useState(false);
  const timer = useRef(null);

  const show = () => {
    timer.current = setTimeout(() => setOpen(true), delay);
  };
  const hide = () => {
    clearTimeout(timer.current);
    setOpen(false);
  };

  useEffect(() => () => clearTimeout(timer.current), []);

  return (
    <span
      style={{ position: 'relative', display: 'inline-block' }}
      onMouseEnter={show}
      onMouseLeave={hide}
      onFocus={show}
      onBlur={hide}
    >
      {children}
      {open && (
        <span
          role="tooltip"
          style={{
            position: 'absolute',
            bottom: '100%',
            left: '50%',
            transform: 'translateX(-50%)',
            marginBottom: 8,
            background: '#222',
            color: '#fff',
            padding: '6px 10px',
            borderRadius: 6,
            fontSize: 13,
            whiteSpace: 'nowrap',
            zIndex: 10,
          }}
        >
          {text}
          <span
            style={{
              position: 'absolute',
              top: '100%',
              left: '50%',
              transform: 'translateX(-50%)',
              borderWidth: 5,
              borderStyle: 'solid',
              borderColor: '#222 transparent transparent transparent',
            }}
          />
        </span>
      )}
    </span>
  );
}

