import { Component, Input, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-tooltip',
  template: `
    <span
      style="position: relative; display: inline-block;"
      (mouseenter)="show()"
      (mouseleave)="hide()"
      (focusin)="show()"
      (focusout)="hide()"
    >
      <ng-content></ng-content>
      <span
        *ngIf="open"
        role="tooltip"
        style="position: absolute; bottom: 100%; left: 50%; transform: translateX(-50%); margin-bottom: 8px; background: #222; color: #fff; padding: 6px 10px; border-radius: 6px; font-size: 13px; white-space: nowrap; z-index: 10;"
      >
        {{ text }}
        <span style="position: absolute; top: 100%; left: 50%; transform: translateX(-50%); border-width: 5px; border-style: solid; border-color: #222 transparent transparent transparent;"></span>
      </span>
    </span>
  `,
})
export class TooltipComponent implements OnDestroy {
  @Input() text = '';
  @Input() delay = 200;
  open = false;
  private timer: any = null;

  show(): void {
    this.timer = setTimeout(() => {
      this.open = true;
    }, this.delay);
  }

  hide(): void {
    clearTimeout(this.timer);
    this.open = false;
  }

  ngOnDestroy(): void {
    clearTimeout(this.timer);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 60px; text-align: center;">
      <h1>Tooltip Demo</h1>
      <p>
        Hover or focus the button:
        <app-tooltip text="Saves your changes">
          <button style="padding: 8px 16px; font-size: 15px; cursor: pointer;">Save</button>
        </app-tooltip>
      </p>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, TooltipComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
